import{_ as e,o,c as i,ag as r}from"./chunks/plugin-vue_export-helper.BxO-FKJB.js";const g=JSON.parse('{"title":"Архетипы","description":"","frontmatter":{"title":"Архетипы","date":"2020-09-18T00:00:00.000Z","head":[["link",{"rel":"canonical","href":"https://alterfo.github.io/posts/2020-09-18-archetypes"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"Архетипы"}],["meta",{"property":"og:description","content":"Oleg Sidorkin — инженер и музыкант. Проекты, инструменты и заметки."}],["meta",{"property":"og:url","content":"https://alterfo.github.io/posts/2020-09-18-archetypes"}],["meta",{"property":"og:image","content":"https://alterfo.github.io/og.png"}],["meta",{"property":"og:site_name","content":"Alterfo"}],["meta",{"property":"og:locale","content":"ru_RU"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Архетипы"}],["meta",{"name":"twitter:description","content":"Oleg Sidorkin — инженер и музыкант. Проекты, инструменты и заметки."}],["meta",{"name":"twitter:image","content":"https://alterfo.github.io/og.png"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BlogPosting\\",\\"headline\\":\\"Архетипы\\",\\"description\\":\\"Oleg Sidorkin — инженер и музыкант. Проекты, инструменты и заметки.\\",\\"url\\":\\"https://alterfo.github.io/posts/2020-09-18-archetypes\\",\\"inLanguage\\":\\"ru-RU\\",\\"author\\":{\\"@type\\":\\"Person\\",\\"name\\":\\"Oleg Sidorkin\\",\\"alternateName\\":\\"alterfo\\",\\"url\\":\\"https://alterfo.github.io\\",\\"jobTitle\\":\\"Software Engineer\\",\\"knowsAbout\\":[\\"Music\\",\\"Audio DSP\\",\\"AI\\",\\"RAG\\",\\"Frontend Development\\",\\"Solution Architecture\\"],\\"sameAs\\":[\\"https://github.com/alterfo\\"]},\\"datePublished\\":\\"2020-09-18\\"}"]]},"headers":[],"relativePath":"posts/2020-09-18-archetypes.md","filePath":"posts/2020-09-18-archetypes.md"}'),p={name:"posts/2020-09-18-archetypes.md"};function a(l,t,n,s,c,u){return o(),i("div",null,[...t[0]||(t[0]=[r("<p>Архетипы как психологическое понятие введено в прошлом веке Карлом Густавом Юнгом для обозначения структурного элемента коллективного бессознательного – захватывающие &quot;изначальные&quot; образы, которые притягивают к себе максимальное количество психической энергии и заставляют эго служить им.</p><p>Классификация опросника PMAI® (Pearson-Marr Archetype Indicator®), основанного на мифологии &quot;путешествия героя&quot; содержит в себе следующие образы (и их потребности), сгруппированные по базовому желанию:</p><p>Структурирование мира:</p><ul><li>Опекун - комфорт</li><li>Правитель - ценности</li><li>Творец - новаторство</li></ul><p>Духовный путь (дорога в рай):</p><ul><li>Невинный - безопасность</li><li>Мудрец - ясность</li><li>Искатель - свобода</li></ul><p>Оставить след:</p><ul><li>Бунтарь - кризис</li><li>Маг - поведение</li><li>Воин - мастерство</li></ul><p>Контакт с другими:</p><ul><li>Сирота (славный малый) - принадлежность</li><li>Любовник - близость</li><li>Шут - удовольствие</li></ul><p>Идеи архетипов в наше время активно используют многие публичные компании при формировании бренда (опять же, репутации). Обратите внимание на то, какие славные малые работают в ИКЕА и как заботится о вас Nivea.</p><p>С понятием архетипов у меня ассоциируется понятие репутации.</p><p>Если вы обнаружили в себе несколько архетипов - это нормально, они все присутствуют в каждом из нас. Идея в том, чтобы не распылять психическую энергию, а выявить доминирующий и уделять ему больше внимания. Чем он более выражен, тем сильнее вы притягиваете к себе внимание людей с этим невыраженным архетипом. Наверное, это можно назвать харизмой.</p><p>Помимо образных архетипов, Юнг ввёл также понятия Анима и Анимус для обозначения гендерных архетипов (да, они оба тоже присутствуют во всех).</p><blockquote><p>Если бы мне нужно было одним словом обозначить то, в чем состоит различие между мужчиной и женщиной в этом отношении, и, таким образом, то, что характеризует анимус в отличии от анимы, то я мог бы сказать только одно: если анима производит настроения, то анимус — мнения, и как настроения мужчины появляются на свет из темных глубин, так и мнения женщин основываются на столь же бессознательных, априорных предпосылках. - Карл Густав Юнг, &quot;Анима и Анимус&quot;</p></blockquote><p>Юнг также указывает на множественность Анимуса (судебная коллегия) и единичность Анимы, это связано, по его мнению, с особенностями мировосприятия. Для Анимы мир состоит из их близких и таких же конгламератов, замкнутых, как правило, на себе. Для Анимуса мир это народ, &quot;государство&quot;. Во снах образ Анимы связан с образом какой-либо из богинь, образ Анимуса это летучие голландцы, всегда неопределенно-неуловимые.</p>",16)])])}const h=e(p,[["render",a]]);export{g as __pageData,h as default};
